import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useTable, useFilters, useGlobalFilter, useAsyncDebounce } from 'react-table';
import { Input } from 'antd';


const { Search } = Input;

function MaterialList() {
  const [material, setMaterial] = useState([]);
  const [newMaterialData, setNewMaterialData] = useState({
    matid: '',
    name: '',
    description: '',
    unit_of_measure: '',
    price_per_unit: 0,
    recent_vendor: '',
  });

  useEffect(() => {
    axios
      .get('http://localhost:8081')
      .then((res) => setMaterial(res.data))
      .catch((err) => console.log(err));
  }, []);

  const handleAddMaterial = () => {
    axios
      .post('http://localhost:8081', newMaterialData)
      .then((res) => {
        setMaterial((prevMaterial) => [...prevMaterial, res.data]);
        setNewMaterialData({
          matid: '',
          name: '',
          description: '',
          unit_of_measure: '',
          price_per_unit: 0,
          recent_vendor: '',
        });
      })
      .catch((err) => console.log(err));
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setNewMaterialData((prevData) => ({ ...prevData, [name]: value }));
  };

  // Define the columns for the table
  const columns = React.useMemo(
    () => [
      {
        Header: 'Material ID',
        accessor: 'matid',
      },
      {
        Header: 'Name',
        accessor: 'name',
      },
      {
        Header: 'Description',
        accessor: 'description',
      },
      {
        Header: 'Unit of Measure',
        accessor: 'unit_of_measure',
      },
      {
        Header: 'Price per Unit',
        accessor: 'price_per_unit',
      },
      {
        Header: 'Recent Vendor',
        accessor: 'recent_vendor',
      },
    ],
    []
  );

  // Create a new table instance
  const {
    getTableProps,
    getTableBodyProps,
    headerGroups,
    rows,
    prepareRow,
    setGlobalFilter,
    state: { globalFilter },
    visibleColumns,
    preFilteredRows,
    setFilter,
  } = useTable(
    {
      columns,
      data: material,
      initialState: { pageIndex: 0 },
    },
    useFilters,
    useGlobalFilter
  );

  const handleColumnSearch = useAsyncDebounce((value, columnId) => {
    setFilter(columnId, value);
  }, 200);

  return (
    <div>
      <div>
        <Search
          value={globalFilter || ''}
          onChange={(e) => setGlobalFilter(e.target.value)}
          placeholder="Search all columns"
          style={{ width: 200 }}
        />
      </div>
      <div>
        <div>
          <label>Material ID:</label>
          <input type="text" name="matid" value={newMaterialData.matid} onChange={handleInputChange} />
        </div>
        {/* Rest of the form inputs */}
        <button className="btn btn-success" onClick={handleAddMaterial}>
          Add+
        </button>
      </div>
      <table {...getTableProps()} className="table">
        <thead>
          {headerGroups.map((headerGroup) => (
            <tr {...headerGroup.getHeaderGroupProps()}>
              {headerGroup.headers.map((column) => (
                <th {...column.getHeaderProps()}>
                  <div>
                    <span>{column.render('Header')}</span>
                    <br />
                    <input
                      type="text"
                      placeholder="Search"
                      onChange={(e) => handleColumnSearch(e.target.value, column.id)}
                    />
                  </div>
                </th>
              ))}
            </tr>
          ))}
        </thead>
        <tbody {...getTableBodyProps()}>
          {rows.map((row) => {
            prepareRow(row);
            return (
              <tr {...row.getRowProps()}>
                {row.cells.map((cell) => (
                  <td {...cell.getCellProps()}>{cell.render('Cell')}</td>
                ))}
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

export default MaterialList;
